import { execFile } from 'node:child_process';

// VULNERABLE — exec() spawns a shell; metacharacters are interpreted
// exec(`convert ${userFile} out.png`)  ->  userFile = 'a.png; rm -rf /'

// SAFE — execFile passes args as an array; no shell, no metachar parsing
execFile('convert', [userFile, 'out.png'], (err) => { /* ... */ });

