// VULNERABLE — IDOR. Any logged-in user can read any invoice by ID.
app.get('/invoices/:id', auth, async (req, res) => {
  const inv = await db.invoice.findById(req.params.id);
  res.json(inv);
});

// SAFE — scope every query by the authenticated principal
app.get('/invoices/:id', auth, async (req, res) => {
  const inv = await db.invoice.findOne({
    id: req.params.id,
    ownerId: req.user.id,        // ownership check in the query itself
  });
  if (!inv) return res.sendStatus(404); // 404, not 403, to avoid leaking existence
  res.json(inv);
});

