import { lookup } from 'node:dns/promises';
import net from 'node:net';

async function assertPublicUrl(raw: string): Promise<URL> {
  const url = new URL(raw);
  if (!['http:', 'https:'].includes(url.protocol)) throw new Error('bad scheme');
  const { address } = await lookup(url.hostname); // resolve, then validate the IP
  if (isPrivate(address)) throw new Error('blocked internal target');
  return url;
}

function isPrivate(ip: string): boolean {
  if (net.isIPv4(ip)) {
    const [a, b] = ip.split('.').map(Number);
    return a === 10 || a === 127 || (a === 169 && b === 254) || // 169.254.x = metadata/link-local
      (a === 172 && b >= 16 && b <= 31) || (a === 192 && b === 168);
  }
  return ip === '::1' || ip.startsWith('fc') || ip.startsWith('fe80');
}

