import { escape as escapeHtml } from 'lodash';

// Allow-list for the only dynamic identifier we accept (A03 / SQLi via ORDER BY)
const SORT_COLUMNS = { title: 'title', created: 'created_at' } as const;
type SortKey = keyof typeof SORT_COLUMNS;

app.get('/docs/search', auth, async (req, res) => {
  const q = typeof req.query.q === 'string' ? req.query.q : '';
  const id = typeof req.query.id === 'string' ? req.query.id : undefined;
  const sortKey = (req.query.sort as string) in SORT_COLUMNS
    ? (req.query.sort as SortKey) : 'created';
  const sortCol = SORT_COLUMNS[sortKey];

  if (id) {
    // FIX A01 Broken Access Control: scope by owner; FIX A03 SQLi: parameterize
    const doc = await db.query(
      'SELECT title, body FROM docs WHERE id = $1 AND owner_id = $2',
      [id, req.user.id]
    );
    if (doc.length === 0) return res.sendStatus(404); // 404, don't leak existence
    // FIX A03 XSS: encode for HTML context (or sanitize if body is rich HTML)
    res.send(
      `<h1>${escapeHtml(doc[0].title)}</h1>` +
      `<div>${escapeHtml(doc[0].body)}</div>`
    );
    return;
  }

  // FIX A03 SQLi: parameterize the LIKE value; escape LIKE wildcards so % and _
  // are treated as literal characters, not user-controlled wildcards.
  const pattern = '%' + q.replace(/[%_\\]/g, '\\$&') + '%';
  const rows = await db.query(
    `SELECT id, title FROM docs
       WHERE title LIKE $1 ESCAPE '\\' AND owner_id = $2
       ORDER BY ${sortCol}`, // sortCol is from a fixed allow-list, never user input
    [pattern, req.user.id]
  );
  res.json(rows);
});

import { lookup } from 'node:dns/promises';
import net from 'node:net';
import http from 'node:http';
import https from 'node:https';

function isBlockedIp(ip: string): boolean {
  if (net.isIPv4(ip)) {
    const [a, b] = ip.split('.').map(Number);
    return (
      a === 0 || a === 127 ||                       // this-host / loopback
      a === 10 ||                                    // RFC1918
      (a === 172 && b >= 16 && b <= 31) ||           // RFC1918
      (a === 192 && b === 168) ||                    // RFC1918
      (a === 169 && b === 254) ||                    // link-local incl. metadata
      (a === 100 && b >= 64 && b <= 127)             // CGNAT 100.64/10
    );
  }
  const lower = ip.toLowerCase();
  return (
    lower === '::1' ||                               // loopback
    lower.startsWith('fc') || lower.startsWith('fd') || // unique-local fc00::/7
    lower.startsWith('fe80') ||                       // link-local
    lower.startsWith('::ffff:')                       // IPv4-mapped: re-check below
  );
}

export async function safeFetch(rawUrl: string): Promise<string> {
  const url = new URL(rawUrl);
  if (url.protocol !== 'http:' && url.protocol !== 'https:') {
    throw new Error('blocked scheme'); // no file:, gopher:, ftp:, etc.
  }

  // Resolve the hostname ourselves and validate the actual IP.
  const { address, family } = await lookup(url.hostname);
  if (isBlockedIp(address)) throw new Error('blocked internal address');

  // Pin the request to the validated IP to defeat DNS rebinding (TOCTOU):
  // the HTTP client will connect to `address`, not re-resolve the name.
  const lib = url.protocol === 'https:' ? https : http;
  return new Promise<string>((resolve, reject) => {
    const req = lib.request(
      {
        host: address,                 // connect to the IP we validated
        servername: url.hostname,      // keep TLS SNI/cert validation correct
        headers: { Host: url.hostname },
        path: url.pathname + url.search,
        port: url.port || (url.protocol === 'https:' ? 443 : 80),
        timeout: 5000,
      },
      (res) => {
        // Do NOT auto-follow redirects into internal targets.
        if (res.statusCode && res.statusCode >= 300 && res.statusCode < 400) {
          res.resume();
          return reject(new Error('redirects disabled')); // or re-run safeFetch on Location
        }
        let size = 0;
        const chunks: Buffer[] = [];
        res.on('data', (c: Buffer) => {
          size += c.length;
          if (size > 2_000_000) { req.destroy(); reject(new Error('too large')); return; }
          chunks.push(c);
        });
        res.on('end', () => resolve(Buffer.concat(chunks).toString('utf8')));
      }
    );
    req.on('timeout', () => req.destroy(new Error('timeout')));
    req.on('error', reject);
    req.end();
  });
}
